        input_path = PROJECT_ROOT / 'data' / 'dfnonvr.csv'
        df_rpm = pd.read_csv(input_path, usecols=['UID', 'rpm-score'])
        log(f"[LOADED] dfnonvr.csv ({len(df_rpm)} rows, {len(df_rpm.columns)} cols)")

        # =========================================================================
        # STEP 2: Data Processing and Standardization
        # =========================================================================
        # Tool: Standard pandas operations for data cleaning and standardization
        # What it does: Rename columns, remove missing values, create z-scores
        # Expected output: Clean dataset with UID, rpm_score, rpm_standardized

        log("[PROCESS] Cleaning and standardizing RPM data...")
        
        # Rename column from 'rpm-score' to 'rpm_score' (remove hyphen for easier Python access)
        df_rpm = df_rpm.rename(columns={'rpm-score': 'rpm_score'})
        log(f"[RENAMED] Column 'rpm-score' -> 'rpm_score'")
        
        # Remove rows with missing RPM scores
        initial_count = len(df_rpm)
        df_rpm = df_rpm.dropna(subset=['rpm_score'])
        final_count = len(df_rpm)
        removed_count = initial_count - final_count
        log(f"[CLEANED] Removed {removed_count} rows with missing RPM scores ({final_count} remain)")
        
        # Validate RPM score range (0-12 per DATA_DICTIONARY)
        min_rpm = df_rpm['rpm_score'].min()
        max_rpm = df_rpm['rpm_score'].max()
        mean_rpm = df_rpm['rpm_score'].mean()
        log(f"[RANGE] RPM scores: min={min_rpm}, max={max_rpm}, mean={mean_rpm:.2f}")
        
        if min_rpm < 0 or max_rpm > 12:
            log(f"[WARNING] RPM scores outside expected range [0,12]: min={min_rpm}, max={max_rpm}")
        
        # Create standardized z-score (rpm_standardized)
        # Formula: (x - mean) / std
        rpm_mean = df_rpm['rpm_score'].mean()
        rpm_std = df_rpm['rpm_score'].std()
        df_rpm['rpm_standardized'] = (df_rpm['rpm_score'] - rpm_mean) / rpm_std
        
        # Validate standardization
        z_mean = df_rpm['rpm_standardized'].mean()
        z_std = df_rpm['rpm_standardized'].std()
        log(f"[STANDARDIZED] rpm_standardized: mean={z_mean:.6f}, std={z_std:.6f}")
        
        if abs(z_mean) > 1e-6 or abs(z_std - 1.0) > 1e-6:
            log(f"[WARNING] Standardization check failed: mean should be ~0, std should be ~1")

        log("[DONE] Data processing complete")

        # =========================================================================
