        # Contains: UID, rpm_score (0-12 range), rpm_standardized (z-score)
        # Columns: ['UID', 'rpm_score', 'rpm_standardized']
        output_path = RQ_DIR / 'data' / 'step01_rpm_scores.csv'
        df_rpm.to_csv(output_path, index=False, encoding='utf-8')
